class AreaCalculator {
  calculate(shapes) {
    let area = 0;
    for (let shape of shapes) {
      if (shape.type === 'circle') {
        area += Math.PI * shape.radius ** 2;
      } else if (shape.type === 'square') {
        area += shape.side ** 2;
      }
    }
    return area;
  }
}

